const p = msg.payload;

const required = ['type', 'schema_version', 'timestamp', 'site_id', 'smart_energy', 'smart_city'];
const missing = required.filter(f => p[f] === undefined);

if (missing.length > 0) {
    msg.statusCode = 400;
    msg.payload = { error: 'Missing fields: ' + missing.join(', ') };
    return [null, msg];
}

if (p.type !== 'sim.tick') {
    msg.statusCode = 400;
    msg.payload = { error: 'Invalid type: ' + p.type + ', expected sim.tick' };
    return [null, msg];
}

flow.set('last_tick', p.timestamp);
flow.set('tick_count', (flow.get('tick_count') || 0) + 1);

return [msg, null];

const envelope = msg.payload;
const ts = envelope.timestamp;
const siteId = envelope.site_id;

// Collect all messages to publish
const mqttMessages = [];
let errorCount = 0;

try {
    // --- Smart Energy: Meters ---
    const meters = envelope.smart_energy.meters || [];
    for (const m of meters) {
        const meterId = m.meter_id || m.asset_id || 'unknown';
        mqttMessages.push({
            topic: 'facis/energy/meter/' + meterId,
            qos: 1,
            retain: false,
            payload: JSON.stringify(m)
        });
    }

    // --- Smart Energy: PV Systems ---
    const pvs = envelope.smart_energy.pv || [];
    for (const p of pvs) {
        const pvId = p.pv_system_id || p.asset_id || 'unknown';
        mqttMessages.push({
            topic: 'facis/energy/pv/' + pvId,
            qos: 1,
            retain: false,
            payload: JSON.stringify(p)
        });
    }

    // --- Smart Energy: Weather ---
    const weather = envelope.smart_energy.weather;
    if (weather) {
        mqttMessages.push({
            topic: 'facis/weather/current',
            qos: 0,
            retain: true,
            payload: JSON.stringify(weather)
        });
    }

    // --- Smart Energy: Price ---
    const price = envelope.smart_energy.price;
    if (price) {
        mqttMessages.push({
            topic: 'facis/prices/spot',
            qos: 1,
            retain: true,
            payload: JSON.stringify(price)
        });
    }

    // --- Smart Energy: Consumers ---
    const consumers = envelope.smart_energy.consumers || [];
    for (const c of consumers) {
        const deviceType = c.device_type || c.device_id || 'unknown';
        mqttMessages.push({
            topic: 'facis/loads/' + deviceType,
            qos: 0,
            retain: false,
            payload: JSON.stringify(c)
        });
    }

    // --- Smart City: Streetlights ---
    const lights = envelope.smart_city.streetlights || [];
    for (const l of lights) {
        const zoneId = l.zone_id || 'unknown';
        mqttMessages.push({
            topic: 'facis/city/light/' + zoneId,
            qos: 0,
            retain: false,
            payload: JSON.stringify(l)
        });
    }

    // --- Smart City: Traffic ---
    const traffic = envelope.smart_city.traffic_readings || [];
    for (const t of traffic) {
        const zoneId = t.zone_id || 'unknown';
        mqttMessages.push({
            topic: 'facis/city/traffic/' + zoneId,
            qos: 0,
            retain: false,
            payload: JSON.stringify(t)
        });
    }

    // --- Smart City: Events ---
    const events = envelope.smart_city.events || [];
    for (const e of events) {
        const zoneId = e.zone_id || 'unknown';
        mqttMessages.push({
            topic: 'facis/city/event/' + zoneId,
            qos: 1,
            retain: false,
            payload: JSON.stringify(e)
        });
    }

    // --- Smart City: Weather/Visibility ---
    const cityWeather = envelope.smart_city.visibility;
    if (cityWeather) {
        mqttMessages.push({
            topic: 'facis/city/weather',
            qos: 0,
            retain: true,
            payload: JSON.stringify(cityWeather)
        });
    }

} catch (err) {
    errorCount++;
    node.error('Feed split error: ' + err.message, msg);
}

// Store stats for monitoring
const feedCounts = {
    meters: (envelope.smart_energy.meters || []).length,
    pv: (envelope.smart_energy.pv || []).length,
    weather: envelope.smart_energy.weather ? 1 : 0,
    price: envelope.smart_energy.price ? 1 : 0,
    consumers: (envelope.smart_energy.consumers || []).length,
    lights: (envelope.smart_city.streetlights || []).length,
    traffic: (envelope.smart_city.traffic_readings || []).length,
    events: (envelope.smart_city.events || []).length,
    city_weather: envelope.smart_city.visibility ? 1 : 0
};

flow.set('last_feed_counts', feedCounts);
flow.set('total_messages_published', 
    (flow.get('total_messages_published') || 0) + mqttMessages.length);

// Output 1: Array of MQTT messages (sent to mqtt-publish-loop)
// Output 2: HTTP response
// Output 3: Debug/monitoring
const httpResponse = {
    payload: {
        status: 'accepted',
        timestamp: ts,
        messages_queued: mqttMessages.length,
        feeds: feedCounts,
        errors: errorCount,
        tick_number: flow.get('tick_count') || 0,
        transport: 'mqtt'
    },
    statusCode: 200,
    req: msg.req,
    res: msg.res
};

const debugMsg = {
    payload: {
        tick: flow.get('tick_count'),
        timestamp: ts,
        mode: envelope.mode,
        total_messages: mqttMessages.length,
        total_published: flow.get('total_messages_published') || 0,
        transport: 'mqtt'
    }
};

// Send MQTT messages as individual outputs
const mqttOutput = mqttMessages.map(m => ({ payload: m }));
node.send([mqttOutput, null, null]);

return [null, httpResponse, debugMsg];

