// Each incoming msg.payload is an MQTT message descriptor:
// { topic, qos, retain, payload }
const m = msg.payload;

msg.topic = m.topic;
msg.qos = m.qos;
msg.retain = m.retain;
msg.payload = m.payload;

return msg;

const status = msg.status;

if (status.fill === 'green') {
    flow.set('mqtt_connected', true);
    flow.set('mqtt_last_connected', new Date().toISOString());
} else if (status.fill === 'red') {
    flow.set('mqtt_connected', false);
    flow.set('error_count', (flow.get('error_count') || 0) + 1);
    node.warn('MQTT broker disconnected: ' + (status.text || 'unknown'));
}

msg.payload = {
    connected: flow.get('mqtt_connected'),
    last_connected: flow.get('mqtt_last_connected'),
    errors: flow.get('error_count') || 0,
    total_published: flow.get('total_messages_published') || 0
};

return msg;

const mqttConnected = flow.get('mqtt_connected');
const healthy = mqttConnected !== false;

msg.statusCode = healthy ? 200 : 503;
msg.payload = {
    status: healthy ? 'healthy' : 'degraded',
    transport: 'mqtt',
    flow_variant: 'facis-simulation-mqtt',
    mqtt: {
        connected: mqttConnected !== false,
        last_connected: flow.get('mqtt_last_connected') || null,
        broker: 'mqtt:1883'
    },
    stats: {
        tick_count: flow.get('tick_count') || 0,
        last_tick: flow.get('last_tick') || null,
        total_messages_published: flow.get('total_messages_published') || 0,
        last_feed_counts: flow.get('last_feed_counts') || {},
        error_count: flow.get('error_count') || 0
    },
    timestamp: new Date().toISOString()
};

return msg;
